INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('31b9aed1-80da-4d01-8906-074520c84815', 'mt', 1, 1, NULL, 'Matthew Henry', 'Mateus abre com a genealogia de Jesus Cristo, Filho de Davi. Henry observa que Deus cumpre cada promessa feita aos patriarcas. O nascimento virginal de Cristo inaugura a nova criação. Aplicação: Toda a história da redenção converge em Cristo; confie no Deus que cumpre suas promessas.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('89038122-758a-4b7e-b8ff-8a3c94f3610c', 'mt', 2, 1, NULL, 'Matthew Henry', 'Os magos buscam o Rei dos judeus seguindo a estrela; Herodes teme. Henry nota que o evangelho chega primeiro aos gentios humildes enquanto o rei orgulhoso o rejeita. Aplicação: Busque a Cristo com persistência; o orgulho é o maior obstáculo ao evangelho.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('37dc5c11-6791-4aa1-9373-2c75d9ce8619', 'mt', 3, 1, NULL, 'Matthew Henry', 'João Batista pregou o arrependimento; Cristo vem ao batismo. A Trindade se manifesta: o Filho batizado, o Espírito como pomba, o Pai falando do céu. Aplicação: O arrependimento genuíno produz frutos; o batismo de Cristo é garantia do nosso batismo espiritual.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('aa6fce18-be4d-4340-b47e-5dde1d053f0f', 'mt', 4, 1, NULL, 'Matthew Henry', 'Jesus é tentado quarenta dias e vence com a Palavra de Deus. Onde Adão falhou, o segundo Adão triunfou. Aplicação: Arme-se com a Escritura para resistir a toda tentação; Cristo é nossa vitória.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('2fc69767-ab70-4e99-8744-eeadb45803b0', 'mt', 5, 1, NULL, 'Matthew Henry', 'O Sermão do Monte inicia com as bem-aventuranças. Henry enfatiza que Cristo não abole a Lei, mas a cumpre e a aprofunda. A exigência é de coração transformado. Aplicação: A graça muda o coração; busque a justiça que excede a dos fariseus pela fé em Cristo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('7e2ff02b-7166-4f2d-b17a-126cd502be61', 'mt', 6, 1, NULL, 'Matthew Henry', 'Jesus ensina sobre oração, jejum e esmolas feitos em segredo diante do Pai. O Pai-Nosso é o modelo de toda oração cristã. Henry destaca a confiança no Pai provedor. Aplicação: Faça tudo para a glória de Deus; busque primeiro o Reino.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('ac209669-e5e4-4c2d-aa12-dc88d64507b4', 'mt', 7, 1, NULL, 'Matthew Henry', 'A regra de ouro resume a Lei e os Profetas. O caminho estreito é o da disciplina e da cruz. Edificar sobre a Rocha é ouvir e praticar as palavras de Cristo. Aplicação: Examine-se antes de julgar; construa sua vida sobre as palavras do Senhor.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b8df238a-09ac-40a4-a99b-8963fd1b3eab', 'mt', 8, 1, NULL, 'Matthew Henry', 'Jesus cura o leproso, o servo do centurião e a sogra de Pedro. A fé do centurião gentio supera a de Israel. A tempestade acalmada revela a autoridade divina. Aplicação: Traga todas as enfermidades ao Senhor em fé; Ele tem poder sobre toda criação.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('20a20e53-03ee-4b59-ad22-19b5dc630f13', 'mt', 9, 1, NULL, 'Matthew Henry', 'Jesus perdoa e cura o paralítico. Mateus é chamado do cargo desprezado; os colhedores são poucos. Aplicação: Clame pela misericórdia que perdoa e restaura; ore ao Senhor da seara por obreiros.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('6d7acd66-8e5e-4f9a-a35d-ad644f335818', 'mt', 10, 1, NULL, 'Matthew Henry', 'Os Doze são enviados como ovelhas entre lobos; não temam os que matam o corpo. A perseguição é parte do discipulado. Aplicação: Não temas a perseguição; confie que Deus cuida de cada detalhe.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('57395b4a-2f4a-4606-a22b-b6d650dace2f', 'mt', 11, 1, NULL, 'Matthew Henry', 'Jesus testemunha sobre João Batista. O convite: ''Vinde a mim, todos os que estais cansados.'' Henry vê a misericórdia de Cristo que repousa o coração sobrecarregado. Aplicação: Entregue seus fardos a Cristo e aprenda sua mansidão.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('6491e4c7-b303-4e39-b14d-4d1d021988e3', 'mt', 12, 1, NULL, 'Matthew Henry', 'A questão do sábado revela o coração endurecido dos fariseus. O Senhor do sábado traz descanso. A árvore boa produz bom fruto. Aplicação: Guarde a reverência ao Senhor sem cair no legalismo vazio.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a9235cdb-ac26-45e9-8a61-f46da8a77374', 'mt', 13, 1, NULL, 'Matthew Henry', 'As parábolas do Reino revelam os mistérios do evangelho. O entendimento espiritual é dom concedido aos humildes. O campo é o mundo; a ceifa é o julgamento final. Aplicação: Seja boa terra que recebe a Palavra e produz fruto.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('c6cff9be-2bd9-411b-94fb-3cc85b7f3f75', 'mt', 14, 1, NULL, 'Matthew Henry', 'Jesus alimenta cinco mil com cinco pães. Pedro caminha sobre as águas e afunda por duvidar. Aplicação: Mantenha os olhos fixos em Cristo no meio das tempestades; a fé fraca também pode ser restaurada.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('319fd21b-00d4-40ba-a12c-7b64f2da0793', 'mt', 15, 1, NULL, 'Matthew Henry', 'Jesus denuncia as tradições humanas que nulificam a Palavra. A mulher cananeia exibe fé exemplar. Aplicação: Examine suas tradições à luz da Escritura; cultive a fé perseverante.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3c3183b3-5600-43c0-886a-186227a17ae1', 'mt', 16, 1, NULL, 'Matthew Henry', 'Pedro confessa Jesus como o Cristo. A edificação sobre a rocha é a confissão de Cristo. Jesus anuncia sua paixão e chama ao autonegamento. Aplicação: Confesse Cristo publicamente; negue-se a si mesmo e siga a cruz.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('79abb509-d710-452c-a86d-a3f14c47a085', 'mt', 17, 1, NULL, 'Matthew Henry', 'A transfiguração revela a glória divina de Cristo. O menino epiléptico é curado pela oração e pelo jejum. Aplicação: A glória futura fortalece no presente; ore e jejue para vencer o que a força própria não vence.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('70744460-821e-456a-b88b-0cf0f886e145', 'mt', 18, 1, NULL, 'Matthew Henry', 'O maior no Reino é quem se humilha como criança. A parábola do devedor impiedoso mostra a seriedade do perdão recebido. Aplicação: Perdoe de coração assim como você foi perdoado; cuide dos mais fracos na fé.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('62d245f3-6c31-4cb4-a2e3-1916456ba82b', 'mt', 19, 1, NULL, 'Matthew Henry', 'O jovem rico é exemplo de riqueza que impede a entrega total. ''Para Deus tudo é possível.'' Aplicação: Coloque Cristo acima de qualquer apego; a generosidade abre o caminho do Reino.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('129dc5aa-525d-4d63-aaad-89c946d3ec94', 'mt', 20, 1, NULL, 'Matthew Henry', 'A parábola dos trabalhadores na vinha: a graça de Deus não é salário, é dom. Os primeiros podem ser últimos quando a arrogância toma o lugar da gratidão. Aplicação: Sirva com humildade e gratidão, não por barganha com Deus.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a6c88e84-06ac-4775-99c7-e404fdf3e05c', 'mt', 21, 1, NULL, 'Matthew Henry', 'A entrada triunfal e a purificação do Templo revelam o Messias. O figueiro maldito simboliza o judaísmo estéril. Aplicação: Que seu louvor a Cristo seja genuíno; produza frutos do Reino.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('935d7457-c364-4c23-bb7e-d7f42809bd10', 'mt', 22, 1, NULL, 'Matthew Henry', 'A parábola do banquete e o maior mandamento: amar a Deus e ao próximo resume toda a Lei. Aplicação: Aceite o convite do evangelho; ame a Deus com toda a sua força.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('671adde9-c64f-48de-9062-22b649788411', 'mt', 23, 1, NULL, 'Matthew Henry', 'Sete ais contra os escribas e fariseus — a hipocrisia religiosa denunciada por Cristo. Nenhum pecado é mais grave que a religião falsa. Aplicação: Pratique o que prega; seja autêntico diante de Deus e dos homens.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('314ea528-a045-4b2c-8f68-d4eb21368e8b', 'mt', 24, 1, NULL, 'Matthew Henry', 'O discurso escatológico: ninguém sabe o dia ou a hora; portanto, esteja sempre pronto. Aplicação: Viva em vigilância constante; que sua vida seja coerente com a expectativa do retorno de Cristo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3892f307-faca-4cbc-a6ae-3f54214661c3', 'mt', 25, 1, NULL, 'Matthew Henry', 'Os talentos e o juízo das nações: os que servem ao menor dos irmãos servem ao próprio Cristo. Aplicação: Invista seus dons para a glória de Deus; sirva ao próximo como serviria a Cristo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('eff9847f-17b1-49ab-8c80-e9cabb195d43', 'mt', 26, 1, NULL, 'Matthew Henry', 'A última ceia institui o memorial da morte de Cristo; Getsêmani é entrega plena à vontade do Pai. Aplicação: Receba a Ceia com gratidão e exame de coração; não confie na própria força.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('72d059a2-46ad-44b2-ac7e-7f4df50e715d', 'mt', 27, 1, NULL, 'Matthew Henry', 'A crucificação: o Filho de Deus morre entre dois ladrões. O véu rasgado abre acesso ao Pai para sempre. Aplicação: Contemple o custo da redenção; o véu rasgado convida a entrar na presença de Deus.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('4499b49f-de09-464a-9115-0d88db637700', 'mt', 28, 1, NULL, 'Matthew Henry', 'A ressurreição e a grande comissão. O evangelismo nasce da ressurreição e da autoridade universal de Cristo. Aplicação: Vá e faça discípulos confiando que o Senhor ressurreto está com você todos os dias.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('cc96f94a-92a4-4717-8f3e-3485df9fecaa', 'lc', 1, 1, NULL, 'Matthew Henry', 'Lucas apresenta o nascimento de João e de Jesus. O Magnificat exalta a justiça e a misericórdia de Deus. Henry vê o evangelho social: Deus exalta os humildes e derruba os poderosos. Aplicação: Exalte a Deus por sua graça que reverte os padrões humanos.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('66fe2df0-e644-4b42-b7a1-3f8b9b69fe54', 'lc', 2, 1, NULL, 'Matthew Henry', 'O nascimento em Belém; os pastores visitam; Simeão e Ana reconhecem o Messias. O Filho de Deus nasce na pobreza para enriquecer os pobres. Aplicação: Que a casa de Deus e sua Palavra sejam sua paixão desde a juventude.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('db334554-199f-438f-8b70-355601ef4443', 'lc', 3, 1, NULL, 'Matthew Henry', 'João Batista prega o batismo de arrependimento; Cristo é batizado. A genealogia de Lucas remonta a Adão — Cristo é redentor de toda a humanidade. Aplicação: O arrependimento abre o caminho para receber o Espírito Santo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5daadfb3-5293-4571-916f-8502d87d32a6', 'lc', 4, 1, NULL, 'Matthew Henry', 'Jesus vence a tentação; anuncia em Nazaré o cumprimento de Isaías 61; cura em Cafarnaum. O Espírito que desceu no batismo conduz Jesus ao deserto e ao ministério. Aplicação: O mesmo Espírito que ungiu a Cristo habita em você para proclamar boas novas.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b05259c1-c401-4451-8efe-0037ca72bd02', 'lc', 5, 1, NULL, 'Matthew Henry', 'A pesca miraculosa chama Simão. ''Apartai-vos de mim, Senhor, que sou homem pecador'' é o começo do chamado. Aplicação: Reconheça sua indignidade e aceite o chamado de Cristo mesmo assim.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b3a726dc-7d53-46d0-9930-2f65d348fa0d', 'lc', 6, 1, NULL, 'Matthew Henry', 'O Sermão da Planície e as bem-aventuranças. O amor aos inimigos e a regra de ouro. Aplicação: Ame seus inimigos e ore por quem o persegue — este é o padrão do Reino.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3efc59ce-36c5-45d9-93f9-4f7c8b638851', 'lc', 7, 1, NULL, 'Matthew Henry', 'O centurião de fé exemplar; a ressurreição do filho da viúva. A pecadora que ungia os pés de Jesus amou muito porque reconheceu muito perdão. Aplicação: A medida do amor a Cristo é proporcional ao reconhecimento do quanto foi perdoado.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('4d388f52-ae70-4821-97bf-4343db9fad83', 'lc', 8, 1, NULL, 'Matthew Henry', 'O semeador; a tempestade acalmada; a filha de Jairo e a mulher com hemorragia. ''Tua fé te salvou; vai em paz.'' Aplicação: Exerça a fé específica que toca a Cristo e experiencie sua paz restauradora.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e91de690-7cb7-4992-93b0-c63dc5a2cbdd', 'lc', 9, 1, NULL, 'Matthew Henry', 'Envio dos Doze; a multiplicação dos pães; a confissão de Pedro; a transfiguração. ''Negue-se a si mesmo, tome sua cruz cada dia.'' Aplicação: O discipulado diário é de negação própria e seguimento a Cristo até a cruz.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d0493d8f-de6a-467d-88c6-f6f39ccf1d6b', 'lc', 10, 1, NULL, 'Matthew Henry', 'Envio dos setenta; o bom samaritano; Maria e Marta. A contemplação da Palavra é a raiz do serviço genuíno. Aplicação: Sente-se primeiro aos pés de Cristo; o serviço sem contemplação degenera em ansiedade.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('2c800334-de58-4097-a629-dc9fbef38133', 'lc', 11, 1, NULL, 'Matthew Henry', 'Jesus ensina o Pai-Nosso; a parábola do amigo importuno. A persistência na oração não muda Deus, mas nos transforma. Aplicação: Persevere na oração com confiança na bondade do Pai.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('23cebb15-c8e9-4089-b80a-796c2970aae8', 'lc', 12, 1, NULL, 'Matthew Henry', 'A parábola do rico insensato; não esteja ansioso. A riqueza é neciamente acumulada quando a alma não está preparada para a eternidade. Aplicação: Busque ser rico para com Deus, não apenas de bens materiais.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('1a11dabd-275f-42b9-8873-03e08e7521b2', 'lc', 13, 1, NULL, 'Matthew Henry', 'Arrependimento urgente; a mulher curvada liberta; a porta estreita. O tempo da graça tem um limite. Aplicação: Entre pela porta estreita agora; não presuma amanhã para arrepender-se hoje.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('8162492b-259f-40d1-a3be-61d0e99d6ca6', 'lc', 14, 1, NULL, 'Matthew Henry', 'A cura no sábado; o grande banquete; o custo do discipulado. Os inicialmente convidados recusaram por ocupações mundanas. Aplicação: Não deixe as preocupações do mundo afastá-lo do banquete do evangelho.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('43a5772c-9365-46e3-bd3d-25a8ae3d6884', 'lc', 15, 1, NULL, 'Matthew Henry', 'A ovelha perdida, a dracma e o filho pródigo — a maior parábola da misericórdia divina. O pai corre ao encontro do filho: Deus não espera passivo, vai ao encontro do arrependido. Aplicação: Volte ao Pai; Ele já vê você de longe e corre ao seu encontro.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d102b796-e026-4f41-b108-1d25226cebec', 'lc', 16, 1, NULL, 'Matthew Henry', 'O mordomo infiel; o rico e Lázaro. Quem não usa bem as riquezas menores não receberá as maiores. A vida após a morte é real e irreversível. Aplicação: Use seus recursos materiais como mordomia fiel para a eternidade.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('ac102009-fe1b-49ef-b98b-377c73959e96', 'lc', 17, 1, NULL, 'Matthew Henry', 'Dos dez leprosos curados, só o samaritano voltou a agradecer. A gratidão é marca do verdadeiro discípulo. Aplicação: Cultive a gratidão constante; não tome as bênçãos de Deus como algo garantido.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3be6da7b-6bab-4734-9216-a7f572e5637d', 'lc', 18, 1, NULL, 'Matthew Henry', 'A viúva persistente; o fariseu e o publicano; o jovem rico; Bartimeu. Ore com persistência e humildade — Deus ouvirá o coração contrito. Aplicação: Clame por misericórdia sem desanimar.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('323278c7-68a2-43b0-b404-d3c86d5300e8', 'lc', 19, 1, NULL, 'Matthew Henry', 'Zaqueu recebe Jesus em sua casa; a entrada em Jerusalém; o choro de Jesus sobre a cidade. A salvação de Zaqueu é o paradigma — o Filho do Homem veio buscar e salvar o perdido. Aplicação: Deixe Cristo entrar em sua casa e em sua vida hoje.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5828a9db-353b-4767-bf52-2c69928b33c4', 'lc', 20, 1, NULL, 'Matthew Henry', 'A autoridade de Jesus questionada; a parábola dos lavradores; o tributo a César. Cristo silencia todos os adversários com sabedoria sobrenatural. Aplicação: Confie na sabedoria de Cristo para responder as questões difíceis de sua fé.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('7e55015c-5264-4cf3-b672-19e8f9ca2b9f', 'lc', 21, 1, NULL, 'Matthew Henry', 'A viúva que deu tudo ao templo deu mais que os ricos que deram do excesso. Sinais do fim; vigilância como imperativo. Aplicação: Dê de coração; esteja vigilante e orante em todo tempo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a7f8e5e3-4dc1-4e5c-bda0-503cbd69795e', 'lc', 22, 1, NULL, 'Matthew Henry', 'A última ceia; o debate sobre quem é o maior; Getsêmani. O cálice da ceia é penhor da redenção consumada. Aplicação: Receba a Ceia com reverência; o sangue do pacto é a base de toda a segurança eterna.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('142ed594-690c-44f4-8de1-42de8f61a055', 'lc', 23, 1, NULL, 'Matthew Henry', 'O ladrão convertido na cruz: ''hoje estarás comigo no paraíso.'' Ninguém está além do alcance da graça; leve o evangelho a quem está em agonia. Aplicação: A graça final e soberana alcança até o último momento.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('167c85ad-6785-49db-a93c-ae75eb9c9b18', 'lc', 24, 1, NULL, 'Matthew Henry', 'A ressurreição; os discípulos de Emaús; a aparição aos onze; a ascensão. O Cristo ressurreto abre a mente dos discípulos para entenderem as Escrituras. Aplicação: Ore para que Cristo abra sua mente às Escrituras; permaneça até ser revestido do alto.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('2fd292db-ca09-4335-ba29-9d9b1778998a', 'mc', 1, 1, NULL, 'Matthew Henry', 'Marcos inicia sem genealogia — Jesus Cristo, Filho de Deus, age com urgência. João batiza; Jesus é tentado e chama os primeiros discípulos. Aplicação: Responda ao chamado de Cristo com prontidão; não adie a obediência.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('19d688c5-fed7-48ea-a794-eaae3a0949c3', 'mc', 2, 1, NULL, 'Matthew Henry', 'Jesus perdoa o paralítico e come com pecadores. Cristo veio buscar os enfermos espirituais. O Filho do Homem é Senhor do sábado. Aplicação: Reconheça sua necessidade espiritual; o médico da alma está disponível a todos.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('2530ef25-c3ae-46f8-8638-0b00495220be', 'mc', 3, 1, NULL, 'Matthew Henry', 'A mão restaurada no sábado; os Doze são escolhidos. A rejeição pelos seus cumpre a Escritura e inicia o novo Israel. Aplicação: Não endureça o coração diante dos milagres da graça.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('90a71a03-61e2-449c-8337-fa4c6bed0e17', 'mc', 4, 1, NULL, 'Matthew Henry', 'A parábola do semeador; a tempestade acalmada. Somente o bom terreno produz fruto. Aplicação: Cultive um coração receptivo; leve ao Senhor as tempestades que o assustam.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('0142013b-ec4f-484c-842c-1afcc056961d', 'mc', 5, 1, NULL, 'Matthew Henry', 'O endemoninhado liberto; Jairo e a mulher com fluxo de sangue. A fé que atinge Cristo em meio à multidão. Aplicação: Alcance a Cristo com fé específica; Ele nota cada toque crente.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a8970cce-a47a-472a-bf4b-f5d1df27a87d', 'mc', 6, 1, NULL, 'Matthew Henry', 'Jesus rejeitado em Nazaré; os Doze enviados; multiplicação dos pães. A dureza do coração impede os milagres. Aplicação: Abra-se para o que Deus quer fazer; não deixe a familiaridade criar descrença.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e83e5aff-a95c-403f-88b6-8a0aa9222683', 'mc', 7, 1, NULL, 'Matthew Henry', 'Tradições humanas versus Mandamentos de Deus. A mulher siro-fenícia e a persistência em fé. Aplicação: Prefira a Palavra de Deus a qualquer tradição humana; persevere na fé.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('9fc9df0b-1432-4448-83b7-23324c74d415', 'mc', 8, 1, NULL, 'Matthew Henry', 'Segunda multiplicação de pães; Pedro confessa Cristo mas rejeita a cruz. O maior perigo para o discípulo é raciocinar segundo os homens. Aplicação: Aceite todo o Cristo, inclusive a cruz.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d2afc1d9-ab17-4571-8a46-2f60735a300e', 'mc', 9, 1, NULL, 'Matthew Henry', 'A Transfiguração; o menino lunático. ''Este gênero só sai pela oração.'' A impotência espiritual vem da negligência no relacionamento com Deus. Aplicação: Cultive a oração como estilo de vida; sem ela, o poder espiritual definha.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('de7db13d-b7d9-4466-a966-0e440040cfbd', 'mc', 10, 1, NULL, 'Matthew Henry', 'O jovem rico; Bartimeu clamando por misericórdia. O modelo da oração eficaz: insistência, fé, gratidão. Aplicação: Clame por misericórdia sem desanimar; a pobreza espiritual reconhecida abre o caminho para a cura.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('ffd4cb73-65d1-4f9b-be52-78d4798bdee2', 'mc', 11, 1, NULL, 'Matthew Henry', 'Entrada em Jerusalém; purificação do Templo; o figueiro maldito. A oração com fé remove obstáculos impossíveis. Aplicação: Seja corajoso em sua fé; que sua religião produza frutos visíveis.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('4ba2ec6a-cc4e-40c2-a83a-afea54b2af2f', 'mc', 12, 1, NULL, 'Matthew Henry', 'A parábola dos lavradores homicidas; o maior mandamento. Amar a Deus e ao próximo vale mais que todos os holocaustos. Aplicação: Que o amor a Deus e ao próximo seja o princípio organizador de toda a sua vida.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('eae1de03-f012-4754-8c96-44998f3f98d3', 'mc', 13, 1, NULL, 'Matthew Henry', 'O discurso escatológico de Marcos: guerras, perseguições e a vinda do Filho do Homem. A vigilância constante é a única resposta à incerteza sobre o fim. Aplicação: Viva cada dia como se fosse o último; esteja pronto para prestar contas ao Senhor.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('4d7d3358-9eaf-42fa-9568-ab87bd8b67a9', 'mc', 14, 1, NULL, 'Matthew Henry', 'A unção em Betânia; a última ceia; Getsêmani. ''Não a minha vontade, mas a tua.'' A devoção da mulher contrasta com a traição do apóstolo. Aplicação: Ofereça o que tem a Cristo; diga sim à vontade de Deus mesmo que doa.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b78dd697-bf85-4349-863b-7296b34bf2b3', 'mc', 15, 1, NULL, 'Matthew Henry', 'A crucificação; o véu rasgado; o centurião confessa. ''Verdadeiramente este homem era o Filho de Deus.'' Aplicação: Deixe a cruz de Cristo transformar sua visão de Deus, do pecado e da redenção.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('631067df-20dd-4420-a531-1945055cbbdd', 'mc', 16, 1, NULL, 'Matthew Henry', 'A ressurreição; Jesus aparece a Maria e aos onze; a grande comissão. A ressurreição é o fundamento de toda a missão cristã. Aplicação: Anuncie o Cristo ressurreto com ousadia — Ele trabalha junto com você.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3fc8e45f-d6ac-42fe-b61c-f1637e9b4098', 'joo', 1, 1, NULL, 'Matthew Henry', 'No princípio era o Verbo, e o Verbo estava com Deus. A encarnação é o maior milagre da história. João Batista testemunha; os primeiros discípulos seguem o Cordeiro. Aplicação: Creia que Jesus é o Verbo encarnado — Deus que veio ao nosso encontro.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a252bce2-bdc8-4bc0-a267-e40bc72b5cc9', 'joo', 2, 1, NULL, 'Matthew Henry', 'A água transformada em vinho em Caná; a purificação do templo. Cristo renova e purifica. O templo de seu corpo ressuscitará. Aplicação: Deixe Cristo purificar o templo de sua vida; Ele guarda o melhor para o fim.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e13c327e-890f-42b8-8a14-c32a06fa38bf', 'joo', 3, 1, NULL, 'Matthew Henry', 'A conversa com Nicodemos: o novo nascimento e João 3.16. O novo nascimento é obra exclusiva do Espírito Santo. Aplicação: Confie que Deus amou o mundo ao ponto de dar o Filho; creia e tenha vida eterna.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('8ce71fe3-f450-4454-b9bc-bd3be5a4b78d', 'joo', 4, 1, NULL, 'Matthew Henry', 'A samaritana no poço de Jacó: a água viva que sacia para sempre. Cristo cruza toda barreira étnica e social. Os campos já estão brancos para a ceifa. Aplicação: Ofereça a água da Vida sem fronteiras étnicas ou morais.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5940870a-407d-4bf3-b4b5-fb4551ccf435', 'joo', 5, 1, NULL, 'Matthew Henry', 'A cura no tanque de Betesda. Jesus afirma: ''O Pai trabalha e eu trabalho.'' Cinco testemunhos de Cristo: João, as obras, o Pai, as Escrituras, Moisés. Aplicação: Aceite o testemunho das Escrituras sobre Cristo e confie em sua autoridade divina.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('0f6d91e9-65f5-4a98-8efb-3d7c3e660ff0', 'joo', 6, 1, NULL, 'Matthew Henry', 'A multiplicação dos pães e o discurso do pão da vida: ''Eu sou o pão da vida.'' Pedro confessa: ''A quem iremos? Tu tens as palavras da vida eterna.'' Aplicação: Não abandone Cristo nas doutrinas difíceis; Ele é o único pão que sustenta.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('40e009f5-f994-4f38-818b-bf763266e8ed', 'joo', 7, 1, NULL, 'Matthew Henry', 'No último dia da festa: ''Se alguém tem sede, venha a mim e beba.'' O convite universal do evangelho. Aplicação: Responda ao convite com sede genuína; a água é o Espírito Santo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('f0572368-c4ad-4b7d-846f-72627283a449', 'joo', 8, 1, NULL, 'Matthew Henry', 'A mulher surpreendida em adultério; ''Eu sou a luz do mundo.'' A verdade liberta. Cristo não condena mas liberta do pecado. Aplicação: Venha à luz de Cristo; a verdade produz verdadeira liberdade.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5cd5384e-05f2-4ce1-bda5-df4aae07f071', 'joo', 9, 1, NULL, 'Matthew Henry', 'O cego de nascença curado. A cegueira foi oportunidade para manifestar as obras de Deus. O farisaísmo é a cegueira mais perigosa. Aplicação: Que Cristo abra seus olhos espirituais; reconheça sua cegueira antes de julgar.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('4a642844-50e2-4d6e-ba4a-7aa9f06a9a0a', 'joo', 10, 1, NULL, 'Matthew Henry', '''Eu sou o bom pastor.'' Cristo conhece, dá a vida, tem outras ovelhas, reúne o rebanho, dá a vida eterna. Aplicação: Confie na voz do Pastor que te conhece pelo nome e jamais te abandonará.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d25b0d2d-8a0d-4fab-8033-54d27fa442d0', 'joo', 11, 1, NULL, 'Matthew Henry', 'A ressurreição de Lázaro — ''Eu sou a ressurreição e a vida.'' Jesus chora: prova de sua humanidade plena. Aplicação: Jesus chora com você em seu luto e tem poder de dar vida onde há morte.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3653a2b0-102f-4e1a-92f3-c8266ede6cda', 'joo', 12, 1, NULL, 'Matthew Henry', 'A unção em Betânia; a entrada em Jerusalém. ''Se o grão de trigo não cair e morrer, fica só.'' A lei do grão se aplica ao discípulo. Aplicação: A renúncia a si mesmo produz fruto abundante.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('9469797d-b53b-41aa-8471-59d90f17c473', 'joo', 13, 1, NULL, 'Matthew Henry', 'Jesus lava os pés dos discípulos — o serviço como marca do Reino. O novo mandamento: amar como Cristo amou. Aplicação: Seja servo dos outros; o amor mútuo é o sinal distintivo do cristão.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('6586dba1-628f-4c5b-9fef-29ff987d4aab', 'joo', 14, 1, NULL, 'Matthew Henry', '''Eu sou o caminho, a verdade e a vida.'' O Paráclito prometido é o consolador eterno. Aplicação: Creia que só em Cristo há acesso ao Pai; deixe o Espírito Santo habitar e ensinar.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5166855a-7faa-4d3f-8531-aa01029b7408', 'joo', 15, 1, NULL, 'Matthew Henry', 'A videira verdadeira: ''Permanecei em mim.'' O fruto vem exclusivamente da união vital com Cristo. Aplicação: Cultive o relacionamento íntimo com Cristo; sem Ele, nada podemos fazer.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('910a1ef4-5a95-487c-a86b-b3d3cac24b09', 'joo', 16, 1, NULL, 'Matthew Henry', 'A obra do Espírito: convencerá o mundo de pecado, justiça e juízo. ''Ninguém vos tirará a vossa alegria.'' Aplicação: Confie no Espírito Santo como guia; a alegria de Cristo é mais forte que qualquer tribulação.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('96266058-c34c-45ed-bb4d-e2e2313d3be2', 'joo', 17, 1, NULL, 'Matthew Henry', 'A oração sacerdotal: Cristo intercede por seus discípulos e pelos que creram por meio deles. A unidade é a prova do evangelho. Aplicação: Esteja unido com o povo de Deus; a unidade do corpo é seu testemunho ao mundo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a282b24c-3112-45f3-ba15-ba29a74b0c9c', 'joo', 18, 1, NULL, 'Matthew Henry', 'A prisão de Jesus; a negação de Pedro; Pilatos pergunta ''O que é a verdade?'' diante da Verdade encarnada. Aplicação: Não negue Cristo quando a pressão vier; permita que sua queda se torne restauração.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('006549e5-6a85-434c-84f6-56b904b3f959', 'joo', 19, 1, NULL, 'Matthew Henry', 'A crucificação: ''Está consumado!'' Não é desespero, mas declaração de vitória — toda a obra redentora foi cumprida. Aplicação: A cruz é a obra perfeita de Deus; nada precisa ser acrescentado para sua salvação.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('4ecab237-c23a-4dba-9e84-7ebf84c0fde8', 'joo', 20, 1, NULL, 'Matthew Henry', 'A ressurreição; Tomé confessa: ''Meu Senhor e meu Deus!'' Bem-aventurados os que creem sem ter visto. Aplicação: Creia mesmo sem ver; este é o ápice da revelação em João.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('06655551-7bb7-4108-9b59-0256d8985446', 'joo', 21, 1, NULL, 'Matthew Henry', 'O Cristo ressurreto na praia; a restauração de Pedro: ''Amas-me? Apascenta as minhas ovelhas.'' A graça restaura o que negou. Aplicação: Deixe que Cristo restaure seu fracasso; aceite a comissão de pastorear.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('2ee30288-9226-489d-aa67-697d8ae15934', 'at', 1, 1, NULL, 'Matthew Henry', 'A ascensão de Cristo e a promessa do Espírito. Os discípulos aguardam em oração. A missão começa com espera obediente, não com ativismo precipitado. Aplicação: Antes de agir para Deus, espere pelo poder do Espírito.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('6e954a4d-9938-4729-bdfa-9ce23c369cc1', 'at', 2, 1, NULL, 'Matthew Henry', 'Pentecostes: o Espírito desce como vento e fogo; Pedro prega e três mil se convertem. Nascimento da Igreja e cumprimento de Joel 2. Aplicação: Ore pela efusão do Espírito; o evangelho pregado com poder continua convertendo multidões.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e6785d88-e757-4884-9689-124905f470f2', 'at', 3, 1, NULL, 'Matthew Henry', 'A cura do coxo à porta Formosa. O sinal abre a oportunidade para o evangelho. Aplicação: Sirva com compaixão; os atos de misericórdia abrem corações para o evangelho.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('9ac5f69e-45e3-4388-8ced-a7a0bdd961d9', 'at', 4, 1, NULL, 'Matthew Henry', 'Pedro e João diante do Sinédrio; a oração da Igreja por ousadia. A comunidade primitiva partilhava bens. Aplicação: Ore por ousadia para testemunhar; a comunidade cristã genuína transforma estruturas sociais.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('dcfff5d0-d31d-49c0-a10f-4aad53b7cdb3', 'at', 5, 1, NULL, 'Matthew Henry', 'Ananias e Safira — a mentira ao Espírito Santo. O pecado dentro da Igreja é mais sério que a perseguição de fora. Aplicação: Seja íntegro diante de Deus; a hipocrisia na comunidade de fé é um perigo grave.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('2eff5251-db6e-46dd-a3f1-1985e141e62d', 'at', 6, 1, NULL, 'Matthew Henry', 'Os sete diáconos: o princípio da divisão de trabalho. Líderes oram e pregam; serventes servem em amor. Aplicação: Reconheça os dons distintos no corpo; o serviço humilde é tão espiritual quanto o pregador.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('6e171eb3-1f77-4aa9-b04d-41cf60dbdff0', 'at', 7, 1, NULL, 'Matthew Henry', 'O discurso de Estêvão e seu apedrejamento. ''Senhor, não lhes imputes este pecado.'' O martírio de Estêvão semeou a conversão de Paulo. Aplicação: Perdoe os seus perseguidores; o sofrimento pode ser semente do evangelho.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('29fa5a95-5252-48f8-a341-de084422db3e', 'at', 8, 1, NULL, 'Matthew Henry', 'A perseguição dispersa a Igreja que prega em toda parte. Filipe no Samaria; o etíope que estuda Isaías 53. Deus usa a perseguição para espalhar o evangelho. Aplicação: Não desperdice o sofrimento; o vento da tribulação leva a semente do evangelho mais longe.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('07d36e98-e718-43fc-9f65-9ae64ff76f0a', 'at', 9, 1, NULL, 'Matthew Henry', 'A conversão de Saulo de Tarso na estrada de Damasco. O maior perseguidor se torna o maior apóstolo — ninguém está além da graça. Aplicação: Ore pelas pessoas mais improváveis; Deus pode chamar e transformar qualquer coração.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('0b2cb24d-331d-478f-835f-49e8fa5a9737', 'at', 10, 1, NULL, 'Matthew Henry', 'Cornélio e Pedro — a visão do lençol revela que o evangelho é para todas as nações. Aplicação: Não há pessoas impuras aos olhos de Deus; pregue o evangelho sem preconceito.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a21152c1-fc5b-499e-8bc1-c5ebcc4c6db2', 'at', 11, 1, NULL, 'Matthew Henry', 'Pedro explica a conversão dos gentios. Em Antioquia os discípulos foram chamados pela primeira vez de cristãos. Aplicação: Seja um encorajador como Barnabé; encontre Saulos e invista neles para o Reino.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('56d67bea-269f-4350-a50c-551628cc5172', 'at', 12, 1, NULL, 'Matthew Henry', 'Herodes mata Tiago e prende Pedro; o anjo liberta. A Igreja ora por Pedro enquanto ele bate na porta. Aplicação: Ore com expectativa; Deus responde às vezes antes de terminarmos a oração.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('ce699772-692f-4b77-94b0-08da312032c1', 'at', 13, 1, NULL, 'Matthew Henry', 'A primeira viagem missionária começa com separação pelo Espírito. A missão nasce na adoração e no jejum da comunidade. Aplicação: A missão é responsabilidade da Igreja local; ore e envie missionários com seus recursos.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('75cffd6a-0217-4090-b349-3cb6818716da', 'at', 14, 1, NULL, 'Matthew Henry', 'Curas e perseguições; Paulo é apedrejado e se levanta. ''Por muitas tribulações importa entrar no reino de Deus.'' Aplicação: Aceite o sofrimento como parte do discipulado; o que derruba o servo não derrota o Senhor.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('7c40df94-af5c-4351-8507-97f5f70867bb', 'at', 15, 1, NULL, 'Matthew Henry', 'O Concílio de Jerusalém: o evangelho da graça é confirmado para os gentios. Modelo de resolução de conflitos: diálogo, Escritura, discernimento comunitário. Aplicação: Resolva disputas doutrinárias com a Palavra e oração, não com divisão precipitada.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('95df15fe-a0c9-4b3a-afd6-8341d8273c3c', 'at', 16, 1, NULL, 'Matthew Henry', 'Paulo e Silas em Filipos: Lídia convertida, a escrava curada, o carcereiro convertido. O testemunho em meio ao sofrimento tem poder de converter. Aplicação: Cante hinos na prisão; seu testemunho nas adversidades é mais poderoso que você imagina.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('8111dc29-bf59-4874-8c3e-00e346e3ee35', 'at', 17, 1, NULL, 'Matthew Henry', 'Paulo em Atenas — ''o Deus desconhecido.'' Paulo adapta a mensagem ao contexto cultural sem comprometer o conteúdo. A ressurreição é o ponto de divisão. Aplicação: Apresente o evangelho de forma culturalmente sensível sem diluir a mensagem central.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('7da4f4ee-7f4f-4ebb-af12-d2433fd546a0', 'at', 18, 1, NULL, 'Matthew Henry', 'Paulo em Corinto; Priscila e Áquila ensinam Apolo mais exatamente o caminho de Deus. O discipulado relacional forma líderes. Aplicação: Invista em pessoas com potencial; o discipulado pessoal forma líderes que o ministério público não alcança.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('0c784614-555e-4d2f-942b-f4c01409ba4b', 'at', 19, 1, NULL, 'Matthew Henry', 'Paulo em Éfeso por três anos. O evangelho afeta a economia — o comércio de ídolos desmorona. Aplicação: O evangelho tem consequências culturais; não se iniba ante a resistência dos interesses estabelecidos.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('742ac78d-3e8d-466e-9001-fc7c0ae5f4fa', 'at', 20, 1, NULL, 'Matthew Henry', 'Paulo se despede dos anciãos de Éfeso. Modelo pastoral: trabalho, cuidado, alerta contra falsos ensinos. Aplicação: Pastorei com o coração; a lágrima autêntica é marca do pastor que imita a Paulo e a Cristo.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('28357c08-b91e-4acc-b213-4d2aecd819b2', 'at', 21, 1, NULL, 'Matthew Henry', 'Paulo em Jerusalém; a prisão no Templo. ''Estou pronto não só para ser amarrado, mas também para morrer.'' Aplicação: Que a entrega de Paulo inspire você a não recuar quando o custo do discipulado se tornar claro.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('cc6f2797-a2b1-43cb-87d8-a5bc24c9f14a', 'at', 22, 1, NULL, 'Matthew Henry', 'Paulo relata sua conversão ao povo de Jerusalém. O testemunho pessoal é das mais poderosas ferramentas evangelísticas. Aplicação: Conheça e compartilhe seu testemunho; é uma prova que ninguém pode refutar.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d727bd38-3f73-4cd0-8128-433a5664ac86', 'at', 23, 1, NULL, 'Matthew Henry', 'Paulo perante o Sinédrio; a providência de Deus usando até um sobrinho para salvá-lo. Deus usa meios ordinários para cumprir propósitos extraordinários. Aplicação: Confie na providência; Deus governa cada detalhe.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('fa3baba2-f0a0-40aa-9b6b-0c11a85fb303', 'at', 24, 1, NULL, 'Matthew Henry', 'Paulo perante Félix; a mensagem sobre justiça faz Félix tremer. Tremer sem se arrepender é o destino de muitos. Aplicação: Não pare no tremor; deixe que o temor de Deus produza arrependimento genuíno.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b722b970-39b9-4d83-89ce-8028bc4c823d', 'at', 25, 1, NULL, 'Matthew Henry', 'Paulo apela a César. A prisão de Paulo levou o evangelho a lugares que a liberdade talvez nunca alcançasse. Aplicação: Confie que Deus pode usar suas limitações para abrir portas inesperadas.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a6368644-588c-471f-b1c0-48a57546721e', 'at', 26, 1, NULL, 'Matthew Henry', 'O grande discurso de Paulo perante Agripa. ''Por pouco me persuades a ser cristão.'' A quase-conversão é a tragédia mais comum. Aplicação: Não seja quase cristão; entregue-se completamente.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b5833583-83ad-4c37-a683-8c222e10ccfe', 'at', 27, 1, NULL, 'Matthew Henry', 'A tempestade e o naufrágio; Paulo encoraja e profetiza a sobrevivência. Paulo é âncora de esperança quando todos desesperam. Aplicação: Seja âncora de esperança na tempestade; confie nas promessas de Deus em meio ao caos.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('667d404d-d259-4cf6-a077-7d6617e209be', 'at', 28, 1, NULL, 'Matthew Henry', 'Paulo em Malta; chegada a Roma; dois anos pregando sem impedimento. O evangelho chegou ao centro do mundo. Aplicação: O evangelho continua avançando; sua prisão não é o fim da missão.', 'Matthew Henry', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('11feec77-a036-4c07-8164-657082633792', 'rm', 1, 1, NULL, 'Comentário', 'Paulo apresenta o evangelho — poder de Deus para a salvação. Calvino: a carta aos Romanos é o portal de toda a Escritura. A ira de Deus se revela contra toda impiedade que suprime a verdade. Aplicação: A criação revela Deus suficientemente; proclame o evangelho que é a única resposta.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('1e069787-c8a3-4242-af6a-76b746946046', 'rm', 2, 1, NULL, 'Comentário', 'O juízo de Deus é segundo a verdade, sem acepção de pessoas. O judeu que confia na Lei sem obedecê-la não tem vantagem. A circuncisão que tem valor é a do coração pelo Espírito. Aplicação: Não confie em privilégios religiosos externos; busque a transformação interior.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e234e3db-ff60-45b1-ae32-3aa82973d2c1', 'rm', 3, 1, NULL, 'Comentário', '''Não há justo, nem sequer um.'' Lutero meditou neste capítulo como base de sua reforma: a justificação pela fé, não pelas obras da Lei. A propiciação pelo sangue de Cristo satisfaz a justiça de Deus. Aplicação: A justificação é gratuita pela graça mediante a fé; esta boa nova liberta a consciência cativa.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('220770ad-4cb1-4e61-ae95-67f8ed1b1d79', 'rm', 4, 1, NULL, 'Comentário', 'Abraão creu em Deus e lhe foi imputado por justiça — antes da circuncisão. Lutero exulta: a imputação da justiça de Cristo é a mesma graça oferecida a Abraão. A fé olha para a promessa que dá vida aos mortos. Aplicação: Creia na promessa de Deus contra toda aparência; esta é a fé que justifica.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('8e04c7b0-9d57-4fb6-becb-e5146cb53ff5', 'rm', 5, 1, NULL, 'Comentário', 'Justificados pela fé, temos paz com Deus. O amor de Deus demonstrado na morte de Cristo pelos ímpios. Onde o pecado abundou, a graça superabundou. Aplicação: Glorie-se nas tribulações; elas produzem esperança que não envergonha.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('7174e066-2a72-4b35-a6c0-1572f462e59b', 'rm', 6, 1, NULL, 'Comentário', 'Mortos para o pecado pelo batismo na morte de Cristo; ressuscitamos para andar em novidade de vida. O velho homem foi crucificado para que o corpo do pecado fosse desfeito. Aplicação: Considere-se morto para o pecado e vivo para Deus em Cristo Jesus.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5906cba0-26d9-4bfd-9c46-4539d956b87e', 'rm', 7, 1, NULL, 'Comentário', 'A luta interior: ''Não faço o bem que quero, mas o mal que não quero.'' Paulo descreve a experiência do regenerado que vê a lei do pecado em seus membros. Aplicação: Reconheça a batalha interna como prova de vida espiritual; graças a Deus pela vitória em Cristo.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3656708c-baa5-4b3f-8f1b-7be329c36663', 'rm', 8, 1, NULL, 'Comentário', 'Nenhuma condenação para os que estão em Cristo Jesus. O Espírito que habitou em Cristo habita em você. A cadeia dourada: eleição, chamado, justificação, glorificação. Aplicação: Nada pode separar-nos do amor de Deus em Cristo; esta certeza é fundamento da vida cristã.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e4e58016-3a0d-439b-b09d-fdb205d46da9', 'rm', 9, 1, NULL, 'Comentário', 'A soberania de Deus na eleição: ''Terei misericórdia de quem tiver misericórdia.'' A eleição não é injusta — ninguém merece misericórdia; é graça soberana. Aplicação: Humilhe-se diante do Deus soberano e confie em sua misericórdia.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('250f8fae-93a5-487c-b21a-78e8b004b724', 'rm', 10, 1, NULL, 'Comentário', '''Se com a tua boca confessares ao Senhor Jesus... serás salvo.'' Lutero pregou este versículo como o coração do evangelho. A fé vem pelo ouvir a Palavra pregada. Aplicação: Pregue o evangelho em palavras claras; a fé nasce da proclamação.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('4caf6a64-ab21-4e2c-8e49-7cc876f41d41', 'rm', 11, 1, NULL, 'Comentário', 'O remanescente de Israel; o enxerto das nações; advertência contra o orgulho gentílico. A conclusão é doxologia: ''Ó profundidade das riquezas...'' Aplicação: Maravilhe-se com o plano de Deus para Israel e as nações; adore diante do que não pode compreender.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('43f68fdb-2597-4ade-82de-66c027efb5a1', 'rm', 12, 1, NULL, 'Comentário', 'A consagração do corpo como sacrifício vivo; a renovação da mente; os dons diversificados. Calvino: adoração racional que transforma toda a vida. Aplicação: Apresente seu corpo a Deus; não se conforme com este século — deixe-se transformar.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('db2f1ecf-862e-473b-a17a-cdbf3242db4c', 'rm', 13, 1, NULL, 'Comentário', 'Sujeição às autoridades; o amor como cumprimento da Lei; revesti-vos do Senhor Jesus. Lutero equilibrava: obedecer às autoridades sem idolatrá-las. Aplicação: Seja um cidadão íntegro; o amor ao próximo cumpre todo o mandamento.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('2a84648d-60e2-4ed6-9ba8-6a2b55fb1d0c', 'rm', 14, 1, NULL, 'Comentário', 'Recebei o fraco na fé sem disputas. A liberdade cristã nunca deve tornar-se pedra de tropeço. O Reino de Deus não é comida nem bebida, mas justiça, paz e alegria no Espírito Santo. Aplicação: Exerça sua liberdade com amor; não ponha obstáculo ao irmão mais fraco.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('fdd8ef9c-2ef9-4ecb-a132-164d3e979e6c', 'rm', 15, 1, NULL, 'Comentário', 'O exemplo de Cristo que não agradou a si mesmo. Paulo expõe seu projeto missionário. Calvino: a ambição missionária era chegar onde Cristo não fora anunciado. Aplicação: Tenha visão missionária além do alcançado; interceda pelas fronteiras não alcançadas.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('51b92ecb-3263-43d3-afaa-796a2b1624c6', 'rm', 16, 1, NULL, 'Comentário', 'Saudações a dezenas de colaboradores — homens e mulheres, judeus e gentios. A graça cria comunidades multiétnicas. Guarda-te dos que causam divisões. Aplicação: Valorize cada colaborador no corpo de Cristo; fuja dos que causam divisões doutrinais.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('affee7e0-2917-4ea2-abab-19cc2c82c152', 'gl', 1, 1, NULL, 'Comentário', 'Paulo defende o evangelho recebido por revelação. Não há outro evangelho; qualquer acréscimo à graça é anátema. A repreensão a Pedro mostra que nem apóstolos estão acima da verdade. Aplicação: Defenda o evangelho da graça sem comprometer por pressão social ou tradição.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('aa6d874c-312b-4fdd-997b-c088d0fff5fd', 'gl', 2, 1, NULL, 'Comentário', '''Já estou crucificado com Cristo; e vivo, não mais eu, mas Cristo vive em mim.'' O coração da teologia paulina: a identidade cristã é Cristo vivendo no crente. Aplicação: Viva pela fé no Filho de Deus que vos amou e se entregou por vocês.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('582b7730-5e7f-4064-99d0-b453a090e5a4', 'gl', 3, 1, NULL, 'Comentário', 'Cristo nos resgatou da maldição da lei. Lutero via aqui a base da substituição penal. A bênção de Abraão chega aos gentios pela fé. Aplicação: Cristo tomou a maldição que era sua; você recebeu a bênção que era dele — troca gloriosa.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('bb6bbcd0-d41c-40c2-b5a0-65166ac05ef3', 'gl', 4, 1, NULL, 'Comentário', 'Plena adoção como filhos: ''Deus enviou o Espírito de seu Filho, clamando: Aba, Pai.'' A escravidão à lei é substituída pela liberdade dos filhos adotivos. Aplicação: Clame a Deus como Pai; a adoção é sua identidade mais profunda.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('8b3ffe41-e672-46e9-a7eb-53682ee37005', 'gl', 5, 1, NULL, 'Comentário', 'Para a liberdade foi que Cristo nos libertou. O fruto do Espírito versus as obras da carne. A liberdade cristã não é pretexto para a carne, mas espaço para o amor. Aplicação: Caminhe no Espírito e não cumprirá a concupiscência da carne.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('29d3c39e-a19f-40e5-a1d0-1ad82dcbdb1c', 'gl', 6, 1, NULL, 'Comentário', 'Carregai as cargas uns dos outros e assim cumprireis a lei de Cristo. A glória do cristão é a cruz de Cristo, não as marcas religiosas externas. Aplicação: Sirva ao próximo carregando seus fardos; glorie-se somente na cruz de Cristo.', 'Martinho Lutero', 'commentary', '#047857', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('df6e63c9-409a-4b65-b3dd-31feeb8c24a6', 'ef', 1, 1, NULL, 'Comentário', 'Bendito o Deus que nos abençoou com toda bênção espiritual em Cristo, eleitos antes da fundação do mundo. A eleição é fundamento da segurança e da doxologia cristã. Aplicação: Adore a Deus pela eleição que demonstra sua graça soberana.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e1c9b54c-af0d-40f8-a8db-b6d00b700c4c', 'ef', 2, 1, NULL, 'Comentário', '''Pela graça sois salvos, mediante a fé, e isso não vem de vós; é dom de Deus.'' A salvação da cabeça aos pés é obra de Deus — a fé mesma é dom. Aplicação: Humilhe-se: nada em sua salvação lhe pertence como mérito; glorie-se somente na graça.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('cac39a91-b02f-4f80-8762-eae5623114be', 'ef', 3, 1, NULL, 'Comentário', 'O mistério revelado: os gentios são coherdeiros. A oração de Paulo pela plenitude de Deus no crente. Aplicação: Ore para ser fortalecido pelo Espírito no homem interior e para conhecer o amor de Cristo.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b55bb023-eece-449e-a63e-7b4e6d2472b9', 'ef', 4, 1, NULL, 'Comentário', 'A unidade do corpo: um corpo, um Espírito, uma fé, um batismo. Os dons são dados para equipar os santos. Aplicação: Contribua com seu dom para edificar o corpo; busque a unidade sem sacrificar a verdade.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('dc87981c-20cf-4ede-962f-109834bb3fd3', 'ef', 5, 1, NULL, 'Comentário', 'Sede imitadores de Deus; andai no amor; sede cheios do Espírito. ''Vos enchendo do Espírito'' significa estar sempre sob a influência da Palavra. Aplicação: Que o amor de Cristo molde todos os seus relacionamentos.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b4640d65-eda8-4779-864f-6114c7f378ab', 'ef', 6, 1, NULL, 'Comentário', 'A armadura de Deus para a guerra espiritual. A batalha é contra principados e potestades. A oração mantém tudo unido. Aplicação: Vista toda a armadura de Deus; ore em todo tempo no Espírito por todos os santos.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('948c26f1-3c0f-4e39-83ac-5fef5c0c9e0c', 'fp', 1, 1, NULL, 'Comentário', '''Para mim o viver é Cristo e o morrer é ganho.'' Esta perspectiva só é possível quando Cristo é tudo. Aplicação: Viva de modo digno do evangelho; que Cristo seja honrado em seu corpo, na vida e na morte.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('24386d7f-d847-4693-8822-aa1c041a1cd2', 'fp', 2, 1, NULL, 'Comentário', 'O hino da kênose: Cristo esvaziou-se tomando forma de servo. A humilhação de Cristo é o modelo da humildade do crente. Aplicação: Nada faça por contenda; imite a mente de Cristo que se humilhou até a morte de cruz.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('077c9ae9-42e5-4644-8212-588e7ebfe23b', 'fp', 3, 1, NULL, 'Comentário', 'Paulo lança fora tudo para ganhar a Cristo. ''Prossigo para o alvo, para o prêmio da soberana vocação de Deus.'' Aplicação: Esqueça o que ficou para trás; prossiga com empenho para o alto chamado de Deus.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('384cd939-8012-4ffd-8bb9-f57995f08441', 'fp', 4, 1, NULL, 'Comentário', '''A paz de Deus guardará os vossos corações.'' A anatomia da paz cristã: alegria, ausência de ansiedade, oração, gratidão. Aplicação: Cultive o contentamento em todas as circunstâncias; a paz de Deus é guarda sobrenatural.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('dad8574f-289b-4101-b5d9-e611e80419a8', 'cl', 1, 1, NULL, 'Comentário', 'Cristo é a imagem do Deus invisível, primogênito de toda criação. A supremacia de Cristo é fundamento do evangelho às nações. Aplicação: Que a preeminência de Cristo em tudo organize toda sua vida e teologia.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('baa06511-9679-4224-9ff9-b0a461e3161f', 'cl', 2, 1, NULL, 'Comentário', '''Andai em Cristo, arraigados e edificados nele.'' Cuidado com a filosofia e tradições humanas. Em Cristo estão escondidos todos os tesouros da sabedoria. Aplicação: Nele estão todos os tesouros; não busque sabedoria fora de Cristo.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d162a677-5c18-4770-a3dc-53c9e471a6f1', 'cl', 3, 1, NULL, 'Comentário', 'Buscai as coisas que são de cima; revesti-vos do novo homem. A ressurreição de Cristo se aplica à ética cotidiana: no lar, no trabalho, nos relacionamentos. Aplicação: Que a realidade da ressurreição transforme cada dimensão da sua vida.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('22793434-54af-4de9-bd8a-2839ef68e544', 'cl', 4, 1, NULL, 'Comentário', 'Persevere em oração; ande com sabedoria para com os de fora. A conversa cristã tem graça e discernimento. Aplicação: Que sua fala seja sempre cheia de graça para saber responder a cada um.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('6e7e80e8-32a4-4ecf-b8de-b8d727f8d6e4', 'hb', 1, 1, NULL, 'Comentário', 'Deus fala agora pelo Filho — herdeiro de tudo, sustentáculo do universo. Os puritanos viam neste prólogo a declaração mais clara da divindade de Cristo. Aplicação: Ouça a Deus no Filho; toda a revelação anterior apontava para Cristo.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('654fc5c5-4232-458e-acf6-85133906e0e5', 'hb', 2, 1, NULL, 'Comentário', 'Cristo se fez semelhante aos irmãos para ser o sumo sacerdote misericordioso. A encarnação é indispensável à mediação. Aplicação: Traga suas fraquezas ao sumo sacerdote que as conhece por experiência própria.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e524cffc-4d46-46d5-864d-4d61c9666479', 'hb', 3, 1, NULL, 'Comentário', 'Jesus é superior a Moisés. ''Hoje se ouvirdes a sua voz, não endureçais os vossos corações.'' Aplicação: Não adie a obediência; o hoje da graça pode passar sem retorno.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('8f8d15ab-ea61-45ca-8e31-1dc7591203a7', 'hb', 4, 1, NULL, 'Comentário', 'O repouso que fica para o povo de Deus. O trono da graça é acessível a qualquer hora. Aplicação: Chegue com ousadia ao trono da graça; encontrará misericórdia em tempo oportuno.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5acb6810-22f8-4bc9-a074-bdeeed90df7c', 'hb', 5, 1, NULL, 'Comentário', 'Cristo, sumo sacerdote segundo a ordem de Melquisedeque. O perigo da imaturidade espiritual. Aplicação: Progrida para a maturidade; busque o alimento sólido da Palavra.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('0c8541f5-29c2-4ece-95df-f4f9a8817602', 'hb', 6, 1, NULL, 'Comentário', 'Aviso sério contra a apostasia; mas a âncora da esperança lançada para dentro do véu. Aplicação: Que a promessa e o juramento de Deus sejam âncora firme de sua alma.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('9511591f-2af6-47d1-b6b9-24790da31367', 'hb', 7, 1, NULL, 'Comentário', 'A superioridade do sacerdócio de Cristo: eterno, imutável, perfeito. Cristo ''sempre vive para interceder'' por nós. Aplicação: Confie na intercessão permanente de Cristo; Ele nunca para de orar por você.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('72214595-83a8-4b50-b454-087098cc369a', 'hb', 8, 1, NULL, 'Comentário', 'Cristo é o mediador de um pacto melhor. O novo pacto escreve a Lei no coração. Aplicação: Que a Lei de Deus esteja gravada em seu coração, não apenas observada externamente.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('29cbed87-af6d-4d61-bcff-511735729079', 'hb', 9, 1, NULL, 'Comentário', 'O único sacrifício de Cristo apareceu para anular o pecado pelo seu sacrifício — perfeito e definitivo. Aplicação: Repouse na suficiência do único sacrifício; nada precisa ser acrescentado.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('3c4112ea-530b-4dd5-8532-087acf30fde7', 'hb', 10, 1, NULL, 'Comentário', '''Onde há remissão, não há mais oferta pelo pecado.'' Não abandone a assembleia dos santos. Aplicação: Mantenha a confissão da esperança; encoraje os irmãos e reúna-se com eles regularmente.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5cd28db3-7d70-403b-9079-d16c06c623a8', 'hb', 11, 1, NULL, 'Comentário', 'O hall da fé — todos que viveram pela fé sem ver o cumprimento. ''Sem fé é impossível agradar a Deus.'' Aplicação: Você faz parte desta grande nuvem; viva pela fé nas promessas de Deus.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d6b0109c-ec3b-4db5-afa0-0a9bb02686e7', 'hb', 12, 1, NULL, 'Comentário', 'Olhemos para Jesus, autor e consumador da fé. ''Buscai a santidade, sem a qual ninguém verá o Senhor.'' Aplicação: Corra com perseverança; Deus disciplina os que ama para fazê-los participantes de sua santidade.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d276b15f-06e0-4697-a559-51ea3239fc70', 'hb', 13, 1, NULL, 'Comentário', 'Hospitalidade, castidade, contentamento. ''Nunca te deixarei nem te abandonarei.'' Jesus Cristo é o mesmo ontem, hoje e para sempre. Aplicação: Que o Cristo imutável seja seu fundamento; ofereça sacrifício de louvor continuamente.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('88a09ee0-52b4-418e-a8e2-c7570926f7c9', 'ap', 1, 1, NULL, 'Comentário', 'A revelação de Jesus Cristo glorificado. Cristo aparece glorioso entre os candelabros — presente em sua Igreja. Aplicação: Adore o Cristo glorificado; Ele caminha no meio de sua Igreja.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('bc4d149e-eb7c-4aec-acf4-102892322f1c', 'ap', 2, 1, NULL, 'Comentário', 'Cartas às quatro primeiras igrejas: Éfeso perdeu o primeiro amor; Esmirna sofre; Pérgamo tolera o erro; Tiatira suporta Jezabel. Aplicação: Examine sua comunidade à luz das cartas de Cristo.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('81a29737-48ff-493e-aeb1-f04f08b19867', 'ap', 3, 1, NULL, 'Comentário', 'Sardes é morta; Filadélfia tem porta aberta; Laodiceia é morna. A tibieza é perigosa por ser inconsciente. Aplicação: Não seja morno; abra a porta para Cristo que bate.', 'João Calvino', 'commentary', '#1E40AF', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('98351d45-240a-496a-a67c-8ddc5966649a', 'ap', 4, 1, NULL, 'Comentário', 'O trono celestial e a adoração incessante: ''Santo, Santo, Santo.'' A liturgia celestial é o padrão da adoração terrena — centralidade de Deus. Aplicação: Que sua adoração seja teocêntrica; junte-se à adoração eterna que jamais cessa.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('9fdd57ca-5b77-45be-b71b-fc4cd6cdfdd5', 'ap', 5, 1, NULL, 'Comentário', 'O Cordeiro digno de abrir o livro selado. Toda a história culmina na exaltação do Cordeiro que foi morto. Aplicação: Que o Cordeiro seja o centro de sua teologia, adoração e esperança.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('0b6bc90e-26fc-40f8-b1a4-fab23673735b', 'ap', 19, 1, NULL, 'Comentário', 'O aleluia celestial; as bodas do Cordeiro; o Cavaleiro do cavalo branco — ''REI DOS REIS E SENHOR DOS SENHORES.'' Aplicação: Regozije-se; viva com a esperança do retorno glorioso de Cristo.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('da61e0f3-c542-4f18-b289-e7856eb58b92', 'ap', 20, 1, NULL, 'Comentário', 'O juízo do grande trono branco. Todo ser humano comparecerá diante do juízo final. Aplicação: Viva com consciência da prestação de contas; que isso purifique sua conduta.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b7269393-1de4-47d6-b01c-df3bf5351bbe', 'ap', 21, 1, NULL, 'Comentário', 'O novo céu e a nova terra; a nova Jerusalém. ''Eis que faço novas todas as coisas.'' Aplicação: Viva como cidadão da nova Jerusalém; a esperança transforma como você habita esta terra.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('c9b4b92d-1826-48d6-aaa0-f34b8099d876', 'ap', 22, 1, NULL, 'Comentário', 'O rio da vida; a árvore da vida; ''Vem, Senhor Jesus!'' A esperança que purifica. Aplicação: Que a esperança do retorno de Cristo seja sua motivação para a santidade e a missão.', 'Puritanos', 'commentary', '#6B21A8', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('59e36340-fb84-4b53-b071-438e3d039fbd', 'gn', 1, 1, NULL, 'Referências Cruzadas', 'Jo 1.1; Hb 11.3; Sl 33.6; Pv 8.22-31', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d77426b4-30a0-4f21-a324-243251e7f2d5', 'gn', 3, 15, NULL, 'Referências Cruzadas', 'Rm 16.20; Ap 12.17; Gl 3.16; Hb 2.14', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d920b615-d7b0-4657-a576-2035505796e2', 'gn', 22, 1, NULL, 'Referências Cruzadas', 'Hb 11.17-19; Rm 8.32; Jo 3.16', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('5f467e4b-a1b9-461a-a90e-7dd3ba025400', 'gn', 15, 6, NULL, 'Referências Cruzadas', 'Rm 4.3; Gl 3.6; Tg 2.23', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('071e61e4-65f5-4476-9b10-142051cde822', 'sl', 22, 1, NULL, 'Referências Cruzadas', 'Mt 27.46; Mc 15.34; Hb 5.7', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('0811d476-36d7-4c2d-a88a-652b6413d92f', 'sl', 23, 1, NULL, 'Referências Cruzadas', 'Jo 10.11; Ez 34.23; Hb 13.20', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('ffbd3030-f1b5-404c-8066-99423def4584', 'sl', 110, 1, NULL, 'Referências Cruzadas', 'Mt 22.44; Hb 7.17; At 2.34', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('be1d8c92-0a48-46a7-8052-8304d71cb1c5', 'sl', 51, 1, NULL, 'Referências Cruzadas', 'Rm 7.14-25; 1Jo 1.9; Lm 3.22-23', 'Concordância', 'concordance', NULL, NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('f4218deb-3f71-4884-9df1-61a1efa78403', 'sl', 119, 105, NULL, 'Referências Cruzadas', 'Pv 6.23; 2Tm 3.16; 2Pe 1.19', 'Concordância', 'concordance', NULL, NOW());
